  const midiArray=SimpleMidiParser.parse(data);
  const ppq=midiArray.header.ticksPerBeat;

  let durationInTicks=0;
  const noteMap=new Map();  // Map of note number to start event for tracking durations
  const processedNotes=[];

  // Process all tracks
  for(const track of midiArray.tracks){
    let currentTick=0;

    for(const event of track.events){
      currentTick+=event.deltaTime;

      if(event.type===9){  // Note On
        if(event.data[1]<midiArray.tracks.length+50){  // Valid note range
          const velocity=event.data[2];
          if(velocity>0){  // Actually a note on (not note off with velocity 0)
            if(!noteMap.has(currentTick)){
              noteMap.set(currentTick,{});
            }
            noteMap.get(currentTick)[event.data[1]]=currentTick;
          }
        }
      }
    }

    currentTick=0;
    for(const event of track.events){
      currentTick+=event.deltaTime;

      if(event.type===9&&event.data[2]>0){  // Note On with velocity
        const noteNum=event.data[1];
        // Store start tick
        if(!processedNotes.find(n=>n.noteNum===noteNum&&n.startTick===currentTick)){
          processedNotes.push({noteNum,startTick:currentTick,endTick:currentTick+500});
        }
      }else if(event.type===8||event.type===9&&event.data[2]===0){  // Note Off or Note On with velocity 0
        const noteNum=event.data[1];
        const note=processedNotes.find(n=>n.noteNum===noteNum&&n.endTick<currentTick+100);
        if(note){
          note.endTick=currentTick;
        }
      }
    }

    // Update duration
    const maxTick=Math.max(...processedNotes.map(n=>n.endTick));
    durationInTicks=Math.max(durationInTicks,maxTick);
  }

  // Convert ticks to seconds (assuming 120 BPM, standard MIDI tempo)
  const secondsPerBeat=(60/midiState.tempo)/1000*2000;  // Convert beat duration to seconds
  const tempoMultiplier=1;  // Can be adjusted based on parsed tempo events

  for(const note of processedNotes){
    note.startTime=(note.startTick/ppq)*secondsPerBeat*tempoMultiplier;
    note.endTime=(note.endTick/ppq)*secondsPerBeat*tempoMultiplier;
    note.duration=note.endTime-note.startTime;
  }

  midiState.duration=(durationInTicks/ppq)*secondsPerBeat*tempoMultiplier;
  midiState.notes=processedNotes.filter(n=>n.duration>0.05);  // Filter out very short notes

  console.log(`Parsed tracks: ${midiArray.tracks.length}`);
  console.log(`PPQ: ${ppq}`);
  console.log(`Total events found: ${processedNotes.length}`);
  console.log(`Filtered notes (>50ms): ${midiState.notes.length}`);
  console.log(`Duration: ${midiState.duration.toFixed(1)}s`);
  return true;
}catch(e){
  console.error('MIDI parsing error:',e);
  console.error('Error details:',e.message,e.stack);
  alert(`Failed to parse MIDI file:\n${e.message}\n\nPlease ensure it is a valid MIDI file. Try regenerating with the provided script.`);
  return false;
}

