function renderChordDiagram(chord,voicingIndex=0){
  const voicings=chordVoicingState.voicings[chord.key]||[];
  const voicing=voicings[voicingIndex]||voicings[0];
  const positions=voicing?.positions||[null,null,null,null,null,null];

  // Map note names to their colors for this chord
  const noteColorMap={};
  for(const note of chord.notes){
    if(!noteColorMap[note]){
      noteColorMap[note]=NOTE_COLORS[note]||'#4a9ade';
    }
  }

  const svg=document.createElementNS('http://www.w3.org/2000/svg','svg');
  svg.setAttribute('viewBox','0 0 100 140');
  svg.setAttribute('class','chord-svg');

  const frets=positions.filter(p=>p!==null).map(p=>p.fret);
  const maxFret=frets.length>0?Math.max(...frets):0;
  const minFret=frets.length>0?Math.min(...frets):0;
  const showFrets=Math.min(maxFret+1,5);
  const fretStart=Math.max(0,minFret);

  const fretH=24;
  const stringW=12;
  const startX=15;
  const startY=15;

  // Fret indicator (NUT or fret number)
  if(fretStart===0){
    const nutLine=document.createElementNS('http://www.w3.org/2000/svg','line');
    nutLine.setAttribute('x1',startX-2);
    nutLine.setAttribute('y1',startY);
    nutLine.setAttribute('x2',startX+stringW*5+2);
    nutLine.setAttribute('y2',startY);
    nutLine.setAttribute('stroke','#fff');
    nutLine.setAttribute('stroke-width','3');
    svg.appendChild(nutLine);
  }else{
    const label=document.createElementNS('http://www.w3.org/2000/svg','text');
    label.setAttribute('x',startX-8);
    label.setAttribute('y',startY+8);
    label.setAttribute('font-size','8');
    label.setAttribute('fill','#999');
    label.textContent=fretStart;
    svg.appendChild(label);
  }

  // Fret lines
  for(let f=0;f<=showFrets;f++){
    const y=startY+f*fretH;
    const line=document.createElementNS('http://www.w3.org/2000/svg','line');
    line.setAttribute('x1',startX);
    line.setAttribute('y1',y);
    line.setAttribute('x2',startX+stringW*5);
    line.setAttribute('y2',y);
    line.setAttribute('stroke','#666');
    line.setAttribute('stroke-width','0.5');
    svg.appendChild(line);
  }

  // String lines
  for(let s=0;s<6;s++){
    const x=startX+s*stringW;
    const line=document.createElementNS('http://www.w3.org/2000/svg','line');
    line.setAttribute('x1',x);
    line.setAttribute('y1',startY);
    line.setAttribute('x2',x);
    line.setAttribute('y2',startY+showFrets*fretH);
    line.setAttribute('stroke','#888');
    line.setAttribute('stroke-width','1');
    svg.appendChild(line);
  }

  // String labels
  const tuningDisp=TUNINGS[state.tuning];
  for(let s=0;s<6;s++){
    const x=startX+s*stringW;
    const note=tuningDisp[5-s].replace(/\d/,'');
    const text=document.createElementNS('http://www.w3.org/2000/svg','text');
    text.setAttribute('x',x);
    text.setAttribute('y',startY-5);
    text.setAttribute('text-anchor','middle');
    text.setAttribute('font-size','7');
    text.setAttribute('fill','#999');
    text.textContent=note;
    svg.appendChild(text);
  }


  // Open strings (X or O)
  for(let s=0;s<6;s++){
    const x=startX+s*stringW;
    if(positions[s]===null){
      const xMark=document.createElementNS('http://www.w3.org/2000/svg','text');
      xMark.setAttribute('x',x);
      xMark.setAttribute('y',startY-8);
      xMark.setAttribute('text-anchor','middle');
      xMark.setAttribute('font-size','10');
      xMark.setAttribute('font-weight','bold');
      xMark.setAttribute('fill','#ff6b6b');
      xMark.textContent='✕';
      svg.appendChild(xMark);
    }else if(positions[s].fret===0){
      const circle=document.createElementNS('http://www.w3.org/2000/svg','circle');
      circle.setAttribute('cx',x);
      circle.setAttribute('cy',startY-7);
      circle.setAttribute('r','4');
      circle.setAttribute('fill','none');
      circle.setAttribute('stroke','#4a9ade');
      circle.setAttribute('stroke-width','1.5');
      svg.appendChild(circle);
    }
  }

  // Finger dots
  for(let s=0;s<6;s++){
    if(positions[s]&&positions[s].fret>0){
      const fretPos=positions[s].fret-fretStart;
      const x=startX+s*stringW;
      const y=startY+(fretPos+0.5)*fretH;

      const noteColor=noteColorMap[positions[s].note]||'#4a9ade';

      const circle=document.createElementNS('http://www.w3.org/2000/svg','circle');
      circle.setAttribute('cx',x);
      circle.setAttribute('cy',y);
      circle.setAttribute('r','5');
      circle.setAttribute('fill',noteColor);
      circle.setAttribute('opacity','0.9');
      svg.appendChild(circle);

      const text=document.createElementNS('http://www.w3.org/2000/svg','text');
      text.setAttribute('x',x);
      text.setAttribute('y',y+2.5);
      text.setAttribute('text-anchor','middle');
      text.setAttribute('font-size','6');
      text.setAttribute('fill','#fff');
      text.setAttribute('font-weight','600');
      text.textContent=positions[s].note;
      svg.appendChild(text);
    }
  }

  return svg;
}

// Cycle to next voicing for a chord
function cycleChordVoicing(chordKey){
  const voicingCount=chordVoicingState.voicings[chordKey]?.length||0;
  if(voicingCount===0)return;

  const current=chordVoicingState.currentVoicing[chordKey]||0;
  const next=(current+1)%voicingCount;
  chordVoicingState.currentVoicing[chordKey]=next;

  updateChordDisplay(chordKey);
}

