// Simple MIDI Parser - parsing MIDI files without external dependencies
class SimpleMidiParser {
  static parse(data) {
    const view = new DataView(data);
    let pos = 0;

    // Check MIDI header
    const header = String.fromCharCode(...new Uint8Array(data, pos, 4));
    if (header !== 'MThd') throw new Error('Invalid MIDI file header');
    pos += 4;

    const headerLength = view.getUint32(pos);
    pos += 4;

    const format = view.getUint16(pos);
    pos += 2;

    const numTracks = view.getUint16(pos);
    pos += 2;

    const ticksPerBeat = view.getUint16(pos);
    pos += 2;

    pos += headerLength - 6;

    const tracks = [];

    for (let i = 0; i < numTracks; i++) {
      const trackHeader = String.fromCharCode(...new Uint8Array(data, pos, 4));
      if (trackHeader !== 'MTrk') throw new Error('Invalid track header');
      pos += 4;

      const trackLength = view.getUint32(pos);
      pos += 4;

      const trackEnd = pos + trackLength;
      const events = [];

      let status = 0;

      while (pos < trackEnd) {
        const deltaTime = SimpleMidiParser.readVariableLength(data, pos);
        pos += deltaTime.length;

        let byte = new Uint8Array(data)[pos];

        if (byte & 0x80) {
          status = byte;
          pos++;
        } else if (status === 0) {
          throw new Error('Invalid MIDI: no running status');
        }

        const eventType = (status >> 4) & 0x0f;
        const channel = status & 0x0f;

        let data1 = new Uint8Array(data)[pos] || 0;
        let data2 = 0;

        if ((status & 0xf0) !== 0xc0 && (status & 0xf0) !== 0xd0) {
          pos++;
