          pos += metaLength.length;
          pos += metaLength.value;
        } else {
          events.push({
            deltaTime: deltaTime.value,
            type: (status >> 4) & 0x0f,
            channel: status & 0x0f,
            data: [data1, data2]
          });
        }
      }

      tracks.push({ events });
    }

    return {
      header: { ticksPerBeat, format, numTracks },
      tracks
    };
  }

  static readVariableLength(data, pos) {
    let value = 0;
    let length = 0;

    while (true) {
      const byte = new Uint8Array(data)[pos + length];
      value = (value << 7) | (byte & 0x7f);
