    const arrayBuffer=event.target.result;
    if(parseMidiFile(arrayBuffer)){
      midiState.file=file.name;
      document.getElementById('midi-controls').classList.remove('hidden');
      document.getElementById('midi-info').textContent=`Loaded: ${file.name} (${midiState.notes.length} notes, ${midiState.duration.toFixed(1)}s)`;
      document.getElementById('midi-play-btn').disabled=false;
