// Simple MIDI Parser - parsing MIDI files without external dependencies
class SimpleMidiParser {
  static parse(data) {
    const view = new DataView(data);
    let pos = 0;

    // Check MIDI header
    const header = String.fromCharCode(...new Uint8Array(data, pos, 4));
    if (header !== 'MThd') throw new Error('Invalid MIDI file header');
    pos += 4;

